import React from 'react';
import ReactStrapButton from 'reactstrap/lib/Button';
import merge from 'classnames';

import { Props } from './Button.types';
import styles from './Button.module.scss';

export const Button = (props: Props) => {
  const { children, color, className, ...buttonProps } = props;

  return (
    <ReactStrapButton {...buttonProps} className={merge(styles.button, styles[color], className)}>
      {children}
    </ReactStrapButton>
  );
};

Button.defaultProps = {
  color: 'transparent',
  type: 'button',
  tabIndex: 0,
};
