import { applyMiddleware, compose, createStore, Store, StoreEnhancer } from 'redux';
import createSagaMiddleware, { Saga, Task } from 'redux-saga';

import { AppState } from 'types';

import { rootReducer } from './reducers';
import { allSagas } from './sagas';

type AppStore = Store<AppState>;

const configureStore = (): AppStore => {
  // Create saga middleware
  const sagaMiddleware = createSagaMiddleware();

  // Gather all middlewares
  const allMiddlewares = [sagaMiddleware];

  // Enhance compose function with different enhancers
  const composeEnhancers = (window as any).__REDUX_DEVTOOLS_EXTENSION_COMPOSE__ || compose;

  // Compose all middlewares
  const middleware: StoreEnhancer = composeEnhancers(applyMiddleware(...allMiddlewares));

  // Create Redux store
  const store: AppStore = createStore(rootReducer, middleware);

  // Apply all Sagas
  allSagas.forEach((saga: Saga): Task => sagaMiddleware.run(saga));

  return store;
};

export const store = configureStore();
